        { text: "\u627F\u8AFE\u4E86\u5C31\u4E00\u5B9A\u505A\u5230\u5426\u5247\u4E0D\u8F15\u6613\u627F\u8AFE", color: "blue" },
        { text: "\u53EA\u627F\u8AFE\u6211\u80FD\u638C\u63A7\u7684\u4E8B\u60C5", color: "red" },
        { text: "\u76E1\u91CF\u907F\u514D\u627F\u8AFE\u592A\u591A\u58D3\u529B", color: "green" }
