        { text: "\u5FEB\u7BC0\u594F\u9AD8\u5F37\u5EA6\u6709\u6311\u6230\u6027", color: "red" },
        { text: "\u6162\u7BC0\u594F\u4F4E\u58D3\u529B\u8212\u9069\u6109\u5FEB", color: "green" }
