        { text: "\u6703\u8A8D\u771F\u7814\u7A76\u6700\u9069\u5408\u7684\u54C1\u7A2E\u548C\u990A\u6CD5", color: "blue" },
        { text: "\u8A13\u7DF4\u6709\u7D20\u807D\u5F9E\u6307\u4EE4\u7684\u5BF5\u7269\u6700\u597D", color: "red" },
        { text: "\u5B89\u975C\u6EAB\u9806\u53EF\u4EE5\u975C\u975C\u966A\u4F34\u7684\u5BF5\u7269", color: "green" }
