        { text: "\u6709\u4E9B\u540C\u4E8B\u5408\u5F97\u4F86\u6709\u4E9B\u4E0D\u592A\u884C", color: "blue" },
        { text: "\u6211\u53EA\u5728\u4E4E\u8DDF\u6211\u5DE5\u4F5C\u76F8\u95DC\u7684\u540C\u4E8B\u8868\u73FE", color: "red" }
